1	import { Router } from "express";
2	import { authenticate, requireRole } from "../middleware/auth";
3	import { tenantScope } from "../middleware/tenantScope";
4	import { writeRateLimiter, readRateLimiter } from "../middleware/rateLimiter";
5	import {
6	  handleListOrgs,
7	  handleCreateOrg,
8	  handleUpdateOrg,
9	  handleListAnnouncements,
10	  handleCreateAnnouncement,
11	  handleUpdateAnnouncement,
12	  handleDeleteAnnouncement,
13	  handleListCarouselItems,
14	  handleCreateCarouselItem,
15	  handleUpdateCarouselItem,
16	  handleDeleteCarouselItem,
17	  handleListVenues,
18	  handleCreateVenue,
19	  handleCreateBooking,
20	  handleUpdateBooking,
21	} from "../controllers/admin.controller";
22	
23	const router = Router();
24	router.use(authenticate, tenantScope);
25	
26	const adminOnly = requireRole("ADMINISTRATOR");
27	const modOrAdmin = requireRole("MODERATOR", "ADMINISTRATOR");
28	
29	// Organizations
30	router.get("/admin/organizations", readRateLimiter, adminOnly, handleListOrgs);
31	router.post("/admin/organizations", writeRateLimiter, adminOnly, handleCreateOrg);
32	router.patch("/admin/organizations/:organizationId", writeRateLimiter, adminOnly, handleUpdateOrg);
33	
34	// Announcements вҖ” list is visible to mods/admins; write operations admin-only
35	router.get("/admin/announcements", readRateLimiter, modOrAdmin, handleListAnnouncements);
36	router.post("/admin/announcements", writeRateLimiter, adminOnly, handleCreateAnnouncement);
37	router.patch("/admin/announcements/:announcementId", writeRateLimiter, adminOnly, handleUpdateAnnouncement);
38	router.delete("/admin/announcements/:announcementId", writeRateLimiter, adminOnly, handleDeleteAnnouncement);
39	
40	// Carousel Items
41	router.get("/admin/carousel-items", readRateLimiter, modOrAdmin, handleListCarouselItems);
42	router.post("/admin/carousel-items", writeRateLimiter, adminOnly, handleCreateCarouselItem);
43	router.patch("/admin/carousel-items/:itemId", writeRateLimiter, adminOnly, handleUpdateCarouselItem);
44	router.delete("/admin/carousel-items/:itemId", writeRateLimiter, adminOnly, handleDeleteCarouselItem);
45	
46	// Venues вҖ” all authenticated users can read; writes require admin
47	router.get("/admin/venues", readRateLimiter, handleListVenues);
48	router.post("/admin/venues", writeRateLimiter, adminOnly, handleCreateVenue);
49	router.post("/admin/venues/:venueId/bookings", writeRateLimiter, handleCreateBooking);
50	router.patch("/admin/venue-bookings/:bookingId", writeRateLimiter, handleUpdateBooking);
51	
52	export default router;
