19	// в”Җв”Җв”Җ Thread state machine в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
20	
21	const ALLOWED_TRANSITIONS: Partial<Record<ThreadState, ThreadState[]>> = {
22	  ACTIVE: [ThreadState.LOCKED, ThreadState.ARCHIVED],
23	  LOCKED: [ThreadState.ARCHIVED],
24	  ARCHIVED: [], // irreversible
25	};
26	
27	function assertTransitionAllowed(from: ThreadState, to: ThreadState): void {
28	  const allowed = ALLOWED_TRANSITIONS[from] ?? [];
29	  if (!allowed.includes(to)) {
30	    throw new AppError(
31	      422,
32	      ErrorCode.INVALID_STATE_TRANSITION,
33	      `Cannot transition thread from ${from} to ${to}`
34	    );
35	  }
36	}
37	
38	// в”Җв”Җв”Җ Threads в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
