40	export async function createThread(
41	  organizationId: string,
42	  authorId: string,
43	  input: CreateThreadInput
44	): Promise<ThreadWithIncludes> {
45	  const thread = await threadRepository.create({
46	    ...input,
47	    organizationId,
48	    authorId,
49	  });
50	
51	  await auditRepository.create({
52	    organizationId,
53	    actorId: authorId,
54	    eventType: "thread.created",
55	    resourceType: "Thread",
56	    resourceId: thread.id,
57	    details: { title: thread.title, sectionId: thread.sectionId },
58	  });
59	
60	  void analyticsService.recordEvent({
61	    organizationId,
62	    userId: authorId,
63	    eventType: EVENT.POST_CREATED,
64	    resourceType: "Thread",
65	    resourceId: thread.id,
66	  });
67	
68	  return thread;
69	}
