71	export async function listThreads(
72	  organizationId: string,
73	  query: ListThreadsQuery
74	): Promise<{ data: ThreadWithIncludes[]; total: number }> {
75	  const { tag, page, pageSize, ...filters } = query;
76	  return threadRepository.findMany({
