85	export async function getThread(
86	  threadId: string,
87	  organizationId: string,
88	  viewerId?: string
89	): Promise<ThreadWithIncludes> {
90	  const thread = await threadRepository.findById(threadId, organizationId);
91	  if (!thread) {
92	    throw new AppError(404, ErrorCode.NOT_FOUND, "Thread not found");
93	  }
94	
95	  // Record view event fire-and-forget; internal calls without viewerId are skipped
96	  if (viewerId) {
97	    void analyticsService.recordEvent({
98	      organizationId,
99	      userId: viewerId,
100	      eventType: EVENT.THREAD_VIEW,
101	      resourceType: "Thread",
102	      resourceId: threadId,
103	    });
104	  }
105	
106	  return thread;
107	}
