109	export async function updateThread(
110	  threadId: string,
111	  organizationId: string,
112	  actorId: string,
113	  input: UpdateThreadInput
114	): Promise<Thread> {
115	  const thread = await getThread(threadId, organizationId);
116	
117	  if (thread.state === ThreadState.ARCHIVED) {
118	    throw new AppError(
119	      422,
120	      ErrorCode.THREAD_ARCHIVED,
121	      "Archived thread cannot be edited"
122	    );
123	  }
124	
125	  const updated = await threadRepository.update(threadId, input);
126	
127	  await auditRepository.create({
128	    organizationId,
129	    actorId,
130	    eventType: "thread.updated",
131	    resourceType: "Thread",
132	    resourceId: threadId,
133	    details: input,
134	  });
135	
136	  return updated;
137	}
