139	export async function transitionThreadState(
140	  threadId: string,
141	  organizationId: string,
142	  actorId: string,
143	  input: ThreadStateInput
144	): Promise<Thread> {
145	  const thread = await getThread(threadId, organizationId);
146	  assertTransitionAllowed(thread.state, input.toState);
147	
148	  const updated = await threadRepository.update(threadId, { state: input.toState });
149	
150	  await auditRepository.create({
151	    organizationId,
152	    actorId,
153	    eventType: "thread.state_transitioned",
154	    resourceType: "Thread",
155	    resourceId: threadId,
156	    details: { from: thread.state, to: input.toState },
157	  });
158	
159	  return updated;
160	}
