162	export async function pinThread(
163	  threadId: string,
164	  organizationId: string,
165	  actorId: string
166	): Promise<Thread> {
167	  const thread = await getThread(threadId, organizationId);
168	
169	  if (thread.isPinned) {
170	    throw new AppError(409, ErrorCode.CONFLICT, "Thread is already pinned");
171	  }
172	
173	  const pinnedCount = await threadRepository.countPinned(
174	    organizationId,
175	    thread.sectionId
176	  );
177	  if (pinnedCount >= config.forum.maxPinnedPerSection) {
178	    throw new AppError(
179	      409,
180	      ErrorCode.PIN_LIMIT_REACHED,
181	      `Section already has the maximum of ${config.forum.maxPinnedPerSection} pinned threads`
182	    );
183	  }
184	
185	  const updated = await threadRepository.update(threadId, { isPinned: true });
186	
187	  await auditRepository.create({
188	    organizationId,
189	    actorId,
190	    eventType: "thread.pinned",
191	    resourceType: "Thread",
192	    resourceId: threadId,
193	  });
194	
195	  return updated;
196	}
197	
198	export async function unpinThread(
199	  threadId: string,
200	  organizationId: string,
201	  actorId: string
202	): Promise<Thread> {
203	  const thread = await getThread(threadId, organizationId);
204	
205	  if (!thread.isPinned) {
206	    throw new AppError(409, ErrorCode.CONFLICT, "Thread is not pinned");
207	  }
208	
209	  const updated = await threadRepository.update(threadId, { isPinned: false });
210	
211	  await auditRepository.create({
212	    organizationId,
213	    actorId,
214	    eventType: "thread.unpinned",
215	    resourceType: "Thread",
216	    resourceId: threadId,
217	  });
218	
219	  return updated;
220	}
