222	export async function deleteThread(
223	  threadId: string,
224	  organizationId: string,
225	  actorId: string
226	): Promise<void> {
227	  const thread = await getThread(threadId, organizationId);
228	  const now = new Date();
229	  const expiresAt = new Date(
230	    now.getTime() + config.forum.recycleBinRetentionDays * 86_400_000
231	  );
232	
233	  await threadRepository.softDelete(threadId, now);
234	  await recycleRepository.create({
235	    itemType: "THREAD",
236	    threadId: thread.id,
237	    deletedById: actorId,
238	    deletedAt: now,
239	    expiresAt,
240	  });
241	
242	  await auditRepository.create({
243	    organizationId,
244	    actorId,
245	    eventType: "thread.deleted",
246	    resourceType: "Thread",
247	    resourceId: threadId,
248	  });
249	}
