251	// в”Җв”Җв”Җ Replies в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
252	
253	export async function createReply(
254	  organizationId: string,
255	  authorId: string,
256	  threadId: string,
257	  input: CreateReplyInput
258	): Promise<ReplyWithAuthor> {
259	  const thread = await getThread(threadId, organizationId);
260	
261	  if (thread.state === ThreadState.LOCKED) {
262	    throw new AppError(
263	      422,
264	      ErrorCode.THREAD_LOCKED,
265	      "Thread is locked and cannot accept new replies"
266	    );
267	  }
268	  if (thread.state === ThreadState.ARCHIVED) {
269	    throw new AppError(
270	      422,
271	      ErrorCode.THREAD_ARCHIVED,
272	      "Thread is archived and cannot accept new replies"
273	    );
274	  }
275	
276	  let depth = 1;
277	  const parentReplyId = input.parentReplyId ?? undefined;
278	
279	  if (parentReplyId) {
280	    const parent = await replyRepository.findParent(parentReplyId, threadId);
281	    if (!parent) {
282	      throw new AppError(404, ErrorCode.NOT_FOUND, "Parent reply not found");
283	    }
284	    depth = parent.depth + 1;
285	    if (depth > config.forum.maxReplyDepth) {
286	      throw new AppError(
287	        422,
288	        ErrorCode.REPLY_DEPTH_EXCEEDED,
289	        `Reply nesting exceeds the maximum depth of ${config.forum.maxReplyDepth}`
290	      );
291	    }
292	  }
293	
294	  const reply = await replyRepository.create({
295	    organizationId,
296	    threadId,
297	    authorId,
298	    parentReplyId,
299	    depth,
300	    body: input.body,
301	  });
302	
303	  await auditRepository.create({
304	    organizationId,
305	    actorId: authorId,
306	    eventType: "reply.created",
307	    resourceType: "Reply",
308	    resourceId: reply.id,
309	    details: { threadId, depth },
310	  });
311	
312	  void notifyNewReply(threadId, organizationId, authorId, input.body);
313	
314	  void analyticsService.recordEvent({
315	    organizationId,
316	    userId: authorId,
317	    eventType: EVENT.POST_CREATED,
318	    resourceType: "Reply",
319	    resourceId: reply.id,
320	  });
321	  void analyticsService.recordEvent({
322	    organizationId,
323	    userId: authorId,
324	    eventType: EVENT.ENGAGEMENT,
325	    resourceType: "Thread",
326	    resourceId: threadId,
327	  });
328	
329	  return reply;
330	}
