341	export async function updateReply(
342	  replyId: string,
343	  organizationId: string,
344	  actorId: string,
345	  input: UpdateReplyInput
346	): Promise<ReplyWithAuthor> {
347	  const reply = await replyRepository.findById(replyId, organizationId);
348	  if (!reply) {
349	    throw new AppError(404, ErrorCode.NOT_FOUND, "Reply not found");
350	  }
351	
352	  // thread.organizationId already enforced by findById scoping
353	  if (reply.thread.state === "ARCHIVED") {
354	    throw new AppError(
355	      422,
356	      ErrorCode.THREAD_ARCHIVED,
357	      "Cannot edit a reply in an archived thread"
358	    );
359	  }
360	
361	  await replyRepository.update(replyId, input.body);
362	
363	  await auditRepository.create({
364	    organizationId,
365	    actorId,
366	    eventType: "reply.updated",
367	    resourceType: "Reply",
368	    resourceId: replyId,
369	  });
370	
371	  const updated = await replyRepository.findByIdWithAuthor(replyId, organizationId);
372	  if (!updated) {
373	    throw new AppError(404, ErrorCode.NOT_FOUND, "Reply not found after update");
374	  }
375	  return updated;
376	}
