28	async function createNotification(params: {
29	  organizationId: string;
30	  userId: string;
31	  category: string;
32	  title: string;
33	  body: string;
34	  scheduledAt?: Date;
35	}): Promise<void> {
36	  const { scheduledAt = new Date(), ...rest } = params;
37	
38	  // Security notices bypass subscription opt-out (default opt-in, cannot disable)
39	  if (rest.category !== CATEGORY.SECURITY) {
40	    const sub = await notificationRepository.getSubscription(
41	      rest.userId,
42	      rest.category
43	    );
44	    // Explicit opt-out recorded вҶ’ skip
45	    if (sub && !sub.isOptIn) return;
46	  }
47	
48	  await notificationRepository.create({ ...rest, scheduledAt });
49	}
