1	/**
2	 * Lightweight HTTP client for API tests.
3	 * Uses the native fetch API (Node 20+).
4	 */
5	
6	export const BASE_URL =
7	  (process.env.TEST_BASE_URL ?? "http://localhost:3011").replace(/\/$/, "");
8	
9	type Method = "GET" | "POST" | "PATCH" | "DELETE";
10	
11	export interface ApiResponse<T = Record<string, unknown>> {
12	  status: number;
13	  body: T;
14	  headers: Headers;
15	}
16	
17	async function request<T>(
18	  method: Method,
19	  path: string,
20	  options: {
21	    body?: unknown;
22	    token?: string;
23	    query?: Record<string, string | number | boolean | undefined>;
24	  } = {}
25	): Promise<ApiResponse<T>> {
26	  const url = new URL(`${BASE_URL}/api/v1${path}`);
27	
28	  if (options.query) {
29	    for (const [k, v] of Object.entries(options.query)) {
30	      if (v !== undefined) url.searchParams.set(k, String(v));
31	    }
32	  }
33	
34	  const headers: Record<string, string> = {
35	    "Content-Type": "application/json",
36	  };
37	  if (options.token) {
38	    headers["Authorization"] = `Bearer ${options.token}`;
39	  }
40	
41	  const res = await fetch(url.toString(), {
42	    method,
43	    headers,
44	    body: options.body !== undefined ? JSON.stringify(options.body) : undefined,
45	  });
46	
47	  let body: T;
48	  try {
49	    body = (await res.json()) as T;
50	  } catch {
51	    body = null as unknown as T;
52	  }
53	
54	  return { status: res.status, body, headers: res.headers };
55	}
56	
57	export const api = {
58	  get<T = Record<string, unknown>>(
59	    path: string,
60	    token?: string,
61	    query?: Record<string, string | number | boolean | undefined>
62	  ): Promise<ApiResponse<T>> {
63	    return request<T>("GET", path, { token, query });
64	  },
65	
66	  post<T = Record<string, unknown>>(
67	    path: string,
68	    body?: unknown,
69	    token?: string
70	  ): Promise<ApiResponse<T>> {
71	    return request<T>("POST", path, { body, token });
72	  },
73	
74	  patch<T = Record<string, unknown>>(
75	    path: string,
76	    body?: unknown,
77	    token?: string
78	  ): Promise<ApiResponse<T>> {
79	    return request<T>("PATCH", path, { body, token });
80	  },
81	
82	  del<T = Record<string, unknown>>(
83	    path: string,
84	    token?: string
85	  ): Promise<ApiResponse<T>> {
86	    return request<T>("DELETE", path, { token });
87	  },
88	};
