1	import { Prisma } from "@prisma/client";
2	import { prisma } from "../lib/prisma";
3	
4	// в”Җв”Җв”Җ Event type constants в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
5	
6	export const EVENT = {
7	  THREAD_VIEW: "thread_view",
8	  POST_CREATED: "post_created",
9	  ENGAGEMENT: "engagement",
10	  USER_REGISTERED: "user_registered",
11	} as const;
12	
13	// в”Җв”Җв”Җ Input / Output types в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
14	
15	export interface EventLogInput {
16	  organizationId: string;
17	  userId?: string;
18	  eventType: string;
19	  resourceType?: string;
20	  resourceId?: string;
21	  metadata?: Record<string, unknown>;
22	}
23	
24	export interface FunnelMetrics {
25	  view: number;
26	  registration: number;
27	  post: number;
28	  engagement: number;
29	}
30	
31	export interface DailyCount {
32	  date: string; // YYYY-MM-DD
33	  count: number;
34	}
35	
36	export interface TopThread {
37	  threadId: string;
38	  views: number;
39	}
40	
41	// в”Җв”Җв”Җ Service в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
42	
43	export const analyticsService = {
44	  // в”Җв”Җ Event recording в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
45	
46	  async recordEvent(input: EventLogInput): Promise<void> {
47	    await prisma.eventLog.create({
48	      data: {
49	        organizationId: input.organizationId,
50	        userId: input.userId,
51	        eventType: input.eventType,
52	        resourceType: input.resourceType,
53	        resourceId: input.resourceId,
54	        metadata: (input.metadata ?? {}) as Prisma.InputJsonValue,
55	      },
56	    });
57	  },
58	
59	  // в”Җв”Җ Funnel: view вҶ’ registration вҶ’ post вҶ’ engagement в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
60	
61	  async getFunnelMetrics(
62	    organizationId: string,
63	    from: Date,
64	    to: Date
65	  ): Promise<FunnelMetrics> {
66	    const where = {
67	      organizationId,
68	      createdAt: { gte: from, lte: to },
69	    };
70	
71	    const [views, registrations, posts, engagements] = await Promise.all([
72	      prisma.eventLog.count({ where: { ...where, eventType: EVENT.THREAD_VIEW } }),
73	      prisma.eventLog.count({ where: { ...where, eventType: EVENT.USER_REGISTERED } }),
74	      prisma.eventLog.count({ where: { ...where, eventType: EVENT.POST_CREATED } }),
75	      prisma.eventLog.count({ where: { ...where, eventType: EVENT.ENGAGEMENT } }),
76	    ]);
77	
78	    return { view: views, registration: registrations, post: posts, engagement: engagements };
79	  },
80	
81	  // в”Җв”Җ Daily breakdown for a given event type в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
82	  // Returns one count per calendar day within the range.
83	
84	  async getDailyBreakdown(
85	    organizationId: string,
86	    eventType: string,
87	    from: Date,
88	    to: Date
89	  ): Promise<DailyCount[]> {
90	    // Use Prisma raw groupBy вҖ” PostgreSQL DATE() truncation
91	    const rows = await prisma.$queryRaw<{ day: Date; count: bigint }[]>`
92	      SELECT
93	        DATE_TRUNC('day', "createdAt") AS day,
94	        COUNT(*)::bigint               AS count
95	      FROM "EventLog"
96	      WHERE "organizationId" = ${organizationId}
97	        AND "eventType"       = ${eventType}
98	        AND "createdAt"      >= ${from}
99	        AND "createdAt"      <= ${to}
100	      GROUP BY DATE_TRUNC('day', "createdAt")
101	      ORDER BY day ASC
102	    `;
103	
104	    return rows.map((r) => ({
105	      date: r.day.toISOString().slice(0, 10),
106	      count: Number(r.count),
107	    }));
108	  },
109	
110	  // в”Җв”Җ Top threads by view count в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
111	
112	  async getTopThreads(
113	    organizationId: string,
114	    from: Date,
115	    to: Date,
116	    limit = 10
117	  ): Promise<TopThread[]> {
118	    const rows = await prisma.$queryRaw<{ resourceId: string; count: bigint }[]>`
119	      SELECT
120	        "resourceId",
121	        COUNT(*)::bigint AS count
122	      FROM "EventLog"
123	      WHERE "organizationId" = ${organizationId}
124	        AND "eventType"       = ${EVENT.THREAD_VIEW}
125	        AND "resourceType"    = 'Thread'
126	        AND "resourceId"     IS NOT NULL
127	        AND "createdAt"      >= ${from}
128	        AND "createdAt"      <= ${to}
129	      GROUP BY "resourceId"
130	      ORDER BY count DESC
