1	import { Prisma } from "@prisma/client";
2	import { prisma } from "../lib/prisma";
3	import { logger } from "../lib/logger";
4	import { featureFlagRepository } from "../repositories/feature-flag.repository";
5	
6	/**
7	 * Rule-based risk detection вҖ” creates RiskFlag records for moderator review.
8	 * No automatic punitive actions are taken.
9	 *
10	 * Rules:
11	 *   HIGH_THREAD_DELETIONS  вҖ” actor deletes вүҘN threads in W minutes (defaults: 10, 60)
12	 *   HIGH_CANCELLATIONS     вҖ” actor performs вүҘN content deletions/undos in W minutes (defaults: 20, 60)
13	 *   HIGH_REPORT_VOLUME     вҖ” a thread receives вүҘN reports in W minutes (defaults: 5, 30)
14	 *
15	 * Thresholds are read from FeatureFlag records (key stored in description field) so
16	 * they can be tuned per organisation without redeployment.
17	 */
18	export async function runRiskRules(organizationId: string): Promise<void> {
19	  const now = new Date();
20	
21	  const [
22	    deletionThreshold,
23	    cancellationThreshold,
24	    reportThreshold,
25	    deletionWindowMins,
26	    reportWindowMins,
27	  ] = await Promise.all([
28	    getRiskThreshold(organizationId, "risk.deletion_threshold", 10),
29	    getRiskThreshold(organizationId, "risk.cancellation_threshold", 20),
30	    getRiskThreshold(organizationId, "risk.report_threshold", 5),
31	    getRiskThreshold(organizationId, "risk.deletion_window_minutes", 60),
32	    getRiskThreshold(organizationId, "risk.report_window_minutes", 30),
33	  ]);
34	
35	  const deletionWindowAgo = new Date(now.getTime() - deletionWindowMins * 60_000);
36	  const reportWindowAgo = new Date(now.getTime() - reportWindowMins * 60_000);
37	
38	  await Promise.all([
39	    checkHighThreadDeletions(organizationId, deletionWindowAgo, deletionThreshold),
40	    checkHighCancellations(organizationId, deletionWindowAgo, cancellationThreshold),
41	    checkHighReportVolume(organizationId, reportWindowAgo, reportThreshold),
42	  ]);
43	}
44	
45	// в”Җв”Җв”Җ Rule: вүҘN thread deletions in the deletion window в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
46	
47	async function checkHighThreadDeletions(
48	  organizationId: string,
49	  since: Date,
50	  threshold: number
51	): Promise<void> {
52	  const results = await prisma.auditLog.groupBy({
53	    by: ["actorId"],
54	    where: {
55	      organizationId,
56	      eventType: "thread.deleted",
57	      createdAt: { gte: since },
58	      actorId: { not: null },
59	    },
60	    _count: { id: true },
61	    having: { id: { _count: { gte: threshold } } },
62	  });
63	
64	  for (const r of results) {
65	    if (!r.actorId) continue;
66	    await upsertFlag(
67	      organizationId,
68	      r.actorId,
69	      "User",
70	      "HIGH_THREAD_DELETIONS",
71	      { count: r._count.id, windowStart: since.toISOString(), threshold }
72	    );
73	  }
74	}
75	
76	// в”Җв”Җв”Җ Rule: вүҘN cancellations/undos in the deletion window в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
77	// Counts reply.deleted + recycle_bin.restored events per actor.
78	
79	async function checkHighCancellations(
80	  organizationId: string,
81	  since: Date,
82	  threshold: number
83	): Promise<void> {
84	  const results = await prisma.auditLog.groupBy({
85	    by: ["actorId"],
86	    where: {
87	      organizationId,
88	      eventType: { in: ["reply.deleted", "recycle_bin.restored"] },
89	      createdAt: { gte: since },
90	      actorId: { not: null },
91	    },
92	    _count: { id: true },
93	    having: { id: { _count: { gte: threshold } } },
94	  });
95	
96	  for (const r of results) {
97	    if (!r.actorId) continue;
98	    await upsertFlag(
99	      organizationId,
100	      r.actorId,
101	      "User",
102	      "HIGH_CANCELLATIONS",
103	      { count: r._count.id, windowStart: since.toISOString(), threshold }
104	    );
105	  }
106	}
107	
108	// в”Җв”Җв”Җ Rule: вүҘN reports on a thread in the report window в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
109	
110	async function checkHighReportVolume(
111	  organizationId: string,
112	  since: Date,
113	  threshold: number
114	): Promise<void> {
115	  const results = await prisma.auditLog.groupBy({
116	    by: ["resourceId"],
117	    where: {
118	      organizationId,
119	      eventType: "thread.reported",
120	      createdAt: { gte: since },
121	      resourceId: { not: null },
122	    },
123	    _count: { id: true },
124	    having: { id: { _count: { gte: threshold } } },
125	  });
126	
127	  for (const r of results) {
128	    if (!r.resourceId) continue;
129	    await upsertFlag(
130	      organizationId,
131	      r.resourceId,
132	      "Thread",
133	      "HIGH_REPORT_VOLUME",
134	      { count: r._count.id, windowStart: since.toISOString(), threshold }
135	    );
136	  }
137	}
138	
139	// в”Җв”Җв”Җ Helpers в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
140	
141	async function getRiskThreshold(
142	  organizationId: string,
143	  key: string,
144	  defaultValue: number
145	): Promise<number> {
146	  const flag = await featureFlagRepository.findByKey(organizationId, key);
147	  if (!flag?.description) return defaultValue;
148	  const n = parseInt(flag.description, 10);
149	  return isNaN(n) ? defaultValue : n;
150	}
151	
152	async function upsertFlag(
153	  organizationId: string,
154	  subjectId: string,
155	  subjectType: string,
156	  rule: string,
157	  details: Record<string, unknown>
158	): Promise<void> {
159	  const existing = await prisma.riskFlag.findFirst({
160	    where: { organizationId, subjectId, rule, status: "OPEN" },
161	    select: { id: true },
162	  });
163	
164	  if (existing) {
165	    await prisma.riskFlag.update({
166	      where: { id: existing.id },
167	      data: { details: details as Prisma.InputJsonValue },
168	    });
169	    return;
170	  }
171	
172	  try {
173	    await prisma.riskFlag.create({
174	      data: {
175	        organizationId,
176	        subjectId,
177	        subjectType,
178	        rule,
179	        details: details as Prisma.InputJsonValue,
180	      },
181	    });
182	    logger.warn("Risk flag created", { organizationId, subjectId, rule });
183	  } catch (err) {
184	    logger.error("Risk flag creation failed", {
185	      subjectId,
186	      rule,
187	      error: (err as Error).message,
188	    });
189	  }
190	}
