1	/**
2	 * Database seed script вҖ” creates a default organization and admin user.
3	 * Run: npm run seed
4	 */
5	import { PrismaClient } from "@prisma/client";
6	import bcrypt from "bcryptjs";
7	
8	const prisma = new PrismaClient();
9	
10	async function main(): Promise<void> {
11	  console.log("Seeding database...");
12	
13	  // Create default organization
14	  const org = await prisma.organization.upsert({
15	    where: { slug: "default-org" },
16	    update: {},
17	    create: {
18	      name: "Default Organization",
19	      slug: "default-org",
20	      isActive: true,
21	    },
22	  });
23	  console.log(`Organization: ${org.slug} (${org.id})`);
24	
25	  // Create admin user
26	  const passwordHash = await bcrypt.hash("admin-password-secure", 12);
27	  const admin = await prisma.user.upsert({
28	    where: {
29	      organizationId_username: {
30	        organizationId: org.id,
31	        username: "admin",
32	      },
33	    },
34	    update: {},
35	    create: {
36	      organizationId: org.id,
37	      username: "admin",
38	      passwordHash,
39	      role: "ADMINISTRATOR",
40	    },
41	  });
42	  console.log(`Admin user: ${admin.username} (${admin.id})`);
43	
44	  // Create default section
45	  const section = await prisma.section.upsert({
46	    where: { id: "default-section" },
47	    update: {},
48	    create: {
49	      id: "default-section",
50	      organizationId: org.id,
51	      name: "General Discussion",
52	      description: "General community forum",
53	    },
54	  });
55	  console.log(`Section: ${section.name} (${section.id})`);
56	
57	  // Risk rule thresholds (stored in description field as numeric strings)
58	  const riskThresholds = [
59	    { key: "risk.deletion_threshold",      description: "10" },
60	    { key: "risk.cancellation_threshold",  description: "20" },
61	    { key: "risk.report_threshold",        description: "5"  },
62	    { key: "risk.deletion_window_minutes", description: "60" },
63	    { key: "risk.report_window_minutes",   description: "30" },
64	  ];
65	  for (const f of riskThresholds) {
66	    await prisma.featureFlag.upsert({
67	      where: { organizationId_key: { organizationId: org.id, key: f.key } },
68	      update: {},
69	      create: { organizationId: org.id, key: f.key, value: false, description: f.description },
70	    });
71	  }
72	  console.log("Risk threshold flags seeded.");
73	
74	  console.log("Seed complete.");
75	}
76	
77	main()
78	  .catch((err) => {
79	    console.error("Seed failed:", err);
80	    process.exit(1);
81	  })
82	  .finally(() => prisma.$disconnect());
83

1	/**
2	 * Test database seed вҖ” creates a deterministic set of users, sections, and
3	 * supporting data that API tests depend on.
4	 *
5	 * Run automatically by scripts/entrypoint.test.sh inside the test container.
6	 * Safe to re-run: all operations are idempotent upserts.
7	 */
8	import { PrismaClient, Role } from "@prisma/client";
9	import bcrypt from "bcryptjs";
10	
11	const prisma = new PrismaClient();
12	
13	// в”Җв”Җв”Җ Fixed IDs / slugs used by API tests в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
14	
15	export const TEST_ORG_ID   = "test-org-id";
16	export const TEST_ORG_SLUG = "test-org";
17	
18	export const USER_IDS = {
19	  admin:   "test-admin-id",
20	  mod:     "test-mod-id",
21	  analyst: "test-analyst-id",
22	  user1:   "test-user1-id",
23	  user2:   "test-user2-id",
24	  target:  "test-target-id",   // reserved for ban/mute tests
25	} as const;
26	
27	export const SECTION_IDS = {
28	  alpha: "ts-section-alpha",
29	  beta:  "ts-section-beta",
30	} as const;
31	
32	// в”Җв”Җв”Җ User credential definitions в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
33	
34	const USERS: Array<{
35	  id: string;
36	  username: string;
37	  password: string;
38	  role: Role;
39	}> = [
40	  { id: USER_IDS.admin,   username: "test-admin",   password: "admin-password-secure-1",  role: Role.ADMINISTRATOR },
41	  { id: USER_IDS.mod,     username: "test-mod",     password: "mod-password-secure-1!",   role: Role.MODERATOR     },
42	  { id: USER_IDS.analyst, username: "test-analyst", password: "analyst-pass-secure!1",    role: Role.ANALYST       },
43	  { id: USER_IDS.user1,   username: "test-user1",   password: "user1-password-secure",    role: Role.USER          },
44	  { id: USER_IDS.user2,   username: "test-user2",   password: "user2-password-secure",    role: Role.USER          },
45	  { id: USER_IDS.target,  username: "test-target",  password: "target-pass-secure!1",     role: Role.USER          },
46	];
47	
48	// в”Җв”Җв”Җ Main в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
49	
50	async function main(): Promise<void> {
51	  console.log("[seed-test] Seeding test database...");
52	
53	  // Organization
54	  const org = await prisma.organization.upsert({
55	    where: { slug: TEST_ORG_SLUG },
56	    update: { name: "Test Organization", isActive: true },
57	    create: { id: TEST_ORG_ID, name: "Test Organization", slug: TEST_ORG_SLUG, isActive: true },
58	  });
59	  console.log(`[seed-test] Organization: ${org.slug} (${org.id})`);
60	
61	  // Users
62	  for (const u of USERS) {
63	    const passwordHash = await bcrypt.hash(u.password, 10); // cost 10 for speed in tests
64	    await prisma.user.upsert({
65	      where: { organizationId_username: { organizationId: org.id, username: u.username } },
66	      update: { passwordHash, role: u.role, isBanned: false, muteUntil: null },
67	      create: { id: u.id, organizationId: org.id, username: u.username, passwordHash, role: u.role },
68	    });
69	    console.log(`[seed-test] User: ${u.username} (${u.role})`);
70	  }
71	
72	  // Sections
73	  const sections = [
74	    { id: SECTION_IDS.alpha, name: "Test Section Alpha" },
75	    { id: SECTION_IDS.beta,  name: "Test Section Beta"  },
76	  ];
77	
78	  for (const s of sections) {
79	    await prisma.section.upsert({
80	      where: { id: s.id },
81	      update: { name: s.name },
82	      create: { id: s.id, organizationId: org.id, name: s.name, description: `${s.name} for testing` },
83	    });
84	    console.log(`[seed-test] Section: ${s.name} (${s.id})`);
85	  }
86	
87	  // Tags
88	  const tags = [
89	    { slug: "test-tech",  name: "Technology" },
90	    { slug: "test-news",  name: "News"       },
91	  ];
92	  for (const t of tags) {
93	    await prisma.tag.upsert({
94	      where: { organizationId_slug: { organizationId: org.id, slug: t.slug } },
95	      update: { name: t.name },
96	      create: { organizationId: org.id, name: t.name, slug: t.slug },
97	    });
98	  }
99	  console.log(`[seed-test] Tags seeded`);
100	
101	  // Risk rule thresholds (stored in description field as numeric strings)
102	  const riskThresholds = [
103	    { key: "risk.deletion_threshold",      description: "10" },
104	    { key: "risk.cancellation_threshold",  description: "20" },
105	    { key: "risk.report_threshold",        description: "5"  },
106	    { key: "risk.deletion_window_minutes", description: "60" },
107	    { key: "risk.report_window_minutes",   description: "30" },
108	  ];
109	  for (const f of riskThresholds) {
110	    await prisma.featureFlag.upsert({
111	      where: { organizationId_key: { organizationId: org.id, key: f.key } },
112	      update: {},
113	      create: { organizationId: org.id, key: f.key, value: false, description: f.description },
114	    });
115	  }
116	  console.log("[seed-test] Risk threshold flags seeded.");
117	
118	  console.log("[seed-test] Done.");
119	}
120	
121	main()
122	  .catch((err) => {
123	    console.error("[seed-test] FAILED:", err);
124	    process.exit(1);
125	  })
126	  .finally(() => prisma.$disconnect());
