1	/**
2	 * API tests вҖ” Threads
3	 *
4	 * Covers: CRUD, state machine transitions (including irreversible archived),
5	 * pin limit enforcement, pre/post state verification, and permission checks.
6	 */
7	
8	import { api, loginAs } from "./helpers/client";
9	import { TEST_ORG, CREDS, SECTION_IDS } from "./helpers/fixtures";
10	
11	let adminToken: string;
12	let modToken: string;
13	let userToken: string;
14	
15	// IDs created during setup вҖ” shared within this file
16	let thread1Id: string;   // used for state/pin tests
17	let thread2Id: string;
18	let thread3Id: string;
19	let pinThread1: string;  // used to hit pin limit
20	let pinThread2: string;
21	let pinThread3: string;
22	
23	beforeAll(async () => {
24	  [adminToken, modToken, userToken] = await Promise.all([
25	    loginAs(TEST_ORG, CREDS.admin.username,  CREDS.admin.password),
26	    loginAs(TEST_ORG, CREDS.mod.username,    CREDS.mod.password),
27	    loginAs(TEST_ORG, CREDS.user1.username,  CREDS.user1.password),
28	  ]);
29	
30	  // Create threads used in multiple tests
31	  const [r1, r2, r3, p1, p2, p3] = await Promise.all([
32	    api.post("/threads", { sectionId: SECTION_IDS.alpha, title: "Thread One", body: "Body of thread one" }, userToken),
33	    api.post("/threads", { sectionId: SECTION_IDS.alpha, title: "Thread Two", body: "Body of thread two" }, userToken),
34	    api.post("/threads", { sectionId: SECTION_IDS.alpha, title: "Thread Three", body: "Body of thread three" }, userToken),
35	    api.post("/threads", { sectionId: SECTION_IDS.beta, title: "Pin Test A", body: "Pin body A" }, userToken),
36	    api.post("/threads", { sectionId: SECTION_IDS.beta, title: "Pin Test B", body: "Pin body B" }, userToken),
37	    api.post("/threads", { sectionId: SECTION_IDS.beta, title: "Pin Test C", body: "Pin body C" }, userToken),
38	  ]);
39	
40	  thread1Id   = (r1.body as Record<string, unknown>).id as string;
41	  thread2Id   = (r2.body as Record<string, unknown>).id as string;
42	  thread3Id   = (r3.body as Record<string, unknown>).id as string;
43	  pinThread1  = (p1.body as Record<string, unknown>).id as string;
44	  pinThread2  = (p2.body as Record<string, unknown>).id as string;
45	  pinThread3  = (p3.body as Record<string, unknown>).id as string;
46	});
47	
48	// в”Җв”Җв”Җ Create в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
49	
50	describe("POST /threads", () => {
51	  test("success вҖ” creates thread and returns 201 with full data", async () => {
52	    const res = await api.post(
53	      "/threads",
54	      { sectionId: SECTION_IDS.alpha, title: "New Thread Title", body: "Thread body content here" },
55	      userToken
56	    );
57	    expect(res.status).toBe(201);
58	    const t = res.body as Record<string, unknown>;
59	    expect(t.id).toBeTruthy();
60	    expect(t.title).toBe("New Thread Title");
61	    expect(t.state).toBe("ACTIVE");
62	    expect(t.isPinned).toBe(false);
63	    expect(typeof t.createdAt).toBe("string");
64	  });
65	
66	  test("validation вҖ” missing sectionId returns 400", async () => {
67	    const res = await api.post(
68	      "/threads",
69	      { title: "No Section", body: "Some body" },
70	      userToken
71	    );
72	    expect(res.status).toBe(400);
73	    expect((res.body.error as Record<string, unknown>).code).toBe("VALIDATION_ERROR");
74	  });
75	
76	  test("validation вҖ” missing title returns 400", async () => {
77	    const res = await api.post(
78	      "/threads",
79	      { sectionId: SECTION_IDS.alpha, body: "Some body" },
80	      userToken
81	    );
82	    expect(res.status).toBe(400);
83	  });
84	
85	  test("validation вҖ” missing body returns 400", async () => {
86	    const res = await api.post(
87	      "/threads",
88	      { sectionId: SECTION_IDS.alpha, title: "Title Only" },
89	      userToken
90	    );
91	    expect(res.status).toBe(400);
92	  });
93	
94	  test("auth вҖ” no token returns 401", async () => {
95	    const res = await api.post("/threads", {
96	      sectionId: SECTION_IDS.alpha,
97	      title: "Unauth",
98	      body: "body",
99	    });
100	    expect(res.status).toBe(401);
101	  });
102	});
103	
104	// в”Җв”Җв”Җ List в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
105	
106	describe("GET /threads", () => {
107	  test("success вҖ” returns paginated list", async () => {
108	    const res = await api.get("/threads", userToken);
109	    expect(res.status).toBe(200);
110	    const body = res.body as Record<string, unknown>;
111	    expect(Array.isArray(body.data)).toBe(true);
112	    expect((body.pagination as Record<string, unknown>).total).toBeGreaterThan(0);
113	  });
114	
115	  test("filter by sectionId вҖ” only returns matching threads", async () => {
116	    const res = await api.get("/threads", userToken, { sectionId: SECTION_IDS.beta });
117	    expect(res.status).toBe(200);
118	    const data = (res.body as Record<string, unknown>).data as Array<Record<string, unknown>>;
119	    expect(data.length).toBeGreaterThan(0);
120	    data.forEach((t) => expect(t.sectionId).toBe(SECTION_IDS.beta));
121	  });
122	
123	  test("filter by non-existent section вҖ” returns empty list", async () => {
124	    const res = await api.get("/threads", userToken, { sectionId: "nonexistent-section-id" });
125	    expect(res.status).toBe(200);
126	    const data = (res.body as Record<string, unknown>).data as unknown[];
127	    expect(data).toHaveLength(0);
128	  });
129	});
130	
131	// в”Җв”Җв”Җ Get в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
132	
133	describe("GET /threads/:id", () => {
134	  test("success вҖ” returns thread with author and tags", async () => {
135	    const res = await api.get(`/threads/${thread1Id}`, userToken);
136	    expect(res.status).toBe(200);
137	    const t = res.body as Record<string, unknown>;
138	    expect(t.id).toBe(thread1Id);
139	    expect(t.title).toBe("Thread One");
140	    expect((t.author as Record<string, unknown>).username).toBe(CREDS.user1.username);
141	  });
142	
143	  test("not found вҖ” nonexistent ID returns 404", async () => {
144	    const res = await api.get("/threads/does-not-exist-xyz", userToken);
145	    expect(res.status).toBe(404);
146	    expect((res.body.error as Record<string, unknown>).code).toBe("NOT_FOUND");
147	  });
148	});
149	
150	// в”Җв”Җв”Җ Update (pre/post state verification) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
151	
152	describe("PATCH /threads/:id", () => {
153	  test("success вҖ” title and body update verified pre/post", async () => {
154	    // Pre-state
155	    const before = await api.get(`/threads/${thread2Id}`, userToken);
156	    expect((before.body as Record<string, unknown>).title).toBe("Thread Two");
157	
158	    // Update
159	    const patch = await api.patch(
160	      `/threads/${thread2Id}`,
161	      { title: "Thread Two Updated", body: "Updated body text" },
162	      userToken
163	    );
164	    expect(patch.status).toBe(200);
165	
166	    // Post-state
167	    const after = await api.get(`/threads/${thread2Id}`, userToken);
168	    expect((after.body as Record<string, unknown>).title).toBe("Thread Two Updated");
169	    expect((after.body as Record<string, unknown>).body).toBe("Updated body text");
170	  });
171	
172	  test("auth вҖ” no token returns 401", async () => {
173	    const res = await api.patch(`/threads/${thread2Id}`, { title: "Nope" });
174	    expect(res.status).toBe(401);
175	  });
176	});
177	
178	// в”Җв”Җв”Җ State transitions в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
179	
180	describe("POST /threads/:id/state", () => {
181	  let stateThreadId: string;
182	
183	  beforeAll(async () => {
184	    const r = await api.post(
185	      "/threads",
186	      { sectionId: SECTION_IDS.alpha, title: "State Test Thread", body: "For state machine tests" },
187	      userToken
188	    );
189	    stateThreadId = (r.body as Record<string, unknown>).id as string;
190	  });
191	
192	  test("ACTIVE вҶ’ LOCKED succeeds, state is LOCKED after", async () => {
193	    const res = await api.post(
194	      `/threads/${stateThreadId}/state`,
195	      { toState: "LOCKED" },
196	      modToken
197	    );
198	    expect(res.status).toBe(200);
199	    expect((res.body as Record<string, unknown>).state).toBe("LOCKED");
200	
201	    const get = await api.get(`/threads/${stateThreadId}`, userToken);
202	    expect((get.body as Record<string, unknown>).state).toBe("LOCKED");
203	  });
204	
205	  test("LOCKED вҶ’ ACTIVE is rejected (no rollback)", async () => {
206	    const res = await api.post(
207	      `/threads/${stateThreadId}/state`,
208	      { toState: "ACTIVE" },
209	      modToken
210	    );
211	    expect(res.status).toBe(422);
212	    expect((res.body.error as Record<string, unknown>).code).toBe("INVALID_STATE_TRANSITION");
213	  });
214	
215	  test("LOCKED вҶ’ ARCHIVED succeeds", async () => {
216	    const res = await api.post(
217	      `/threads/${stateThreadId}/state`,
218	      { toState: "ARCHIVED" },
219	      modToken
220	    );
221	    expect(res.status).toBe(200);
222	    expect((res.body as Record<string, unknown>).state).toBe("ARCHIVED");
223	  });
224	
225	  test("ARCHIVED вҶ’ LOCKED is rejected (irreversible)", async () => {
226	    const res = await api.post(
227	      `/threads/${stateThreadId}/state`,
228	      { toState: "LOCKED" },
229	      modToken
230	    );
231	    expect(res.status).toBe(422);
232	    expect((res.body.error as Record<string, unknown>).code).toBe("INVALID_STATE_TRANSITION");
233	  });
234	
235	  test("ARCHIVED вҶ’ ACTIVE is rejected (irreversible)", async () => {
236	    const res = await api.post(
237	      `/threads/${stateThreadId}/state`,
238	      { toState: "ACTIVE" },
239	      modToken
240	    );
241	    expect(res.status).toBe(422);
242	  });
243	
244	  test("permission вҖ” USER role cannot change state (403)", async () => {
245	    const r = await api.post(
246	      "/threads",
247	      { sectionId: SECTION_IDS.alpha, title: "User State Test", body: "body" },
248	      userToken
249	    );
250	    const id = (r.body as Record<string, unknown>).id as string;
251	    const res = await api.post(`/threads/${id}/state`, { toState: "LOCKED" }, userToken);
252	    expect(res.status).toBe(403);
253	    expect((res.body.error as Record<string, unknown>).code).toBe("FORBIDDEN");
254	  });
255	
256	  test("validation вҖ” invalid toState returns 400", async () => {
257	    const r = await api.post(
258	      "/threads",
259	      { sectionId: SECTION_IDS.alpha, title: "Val Test", body: "body" },
260	      userToken
261	    );
262	    const id = (r.body as Record<string, unknown>).id as string;
263	    const res = await api.post(`/threads/${id}/state`, { toState: "PUBLISHED" }, modToken);
264	    expect(res.status).toBe(400);
265	  });
