 * API tests вҖ” Notifications
 *
 * Covers: inbox listing, subscription management, open timestamp tracking,
 * internal dispatch/retry endpoint authorization.
 */

import { api, loginAs, BASE_URL } from "./helpers/client";
import { TEST_ORG, CREDS } from "./helpers/fixtures";

let userToken: string;
let adminToken: string;

const INTERNAL_KEY = process.env.INTERNAL_API_KEY ?? "test-internal-key-secret";

beforeAll(async () => {
  [userToken, adminToken] = await Promise.all([
    loginAs(TEST_ORG, CREDS.user1.username, CREDS.user1.password),
    loginAs(TEST_ORG, CREDS.admin.username, CREDS.admin.password),
  ]);
});

// в”Җв”Җв”Җ Notification inbox в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

describe("GET /notifications", () => {
  test("success вҖ” returns notification list", async () => {
    const res = await api.get("/notifications", userToken);
    expect(res.status).toBe(200);
    const body = res.body as Record<string, unknown>;
    expect(body.data !== undefined || Array.isArray(body)).toBeTruthy();
  });

  test("auth вҖ” no token returns 401", async () => {
    const res = await api.get("/notifications");
    expect(res.status).toBe(401);
  });
});

// в”Җв”Җв”Җ Notification subscriptions в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

describe("Notification subscriptions", () => {
  test("GET /notifications/subscriptions вҖ” returns subscription list", async () => {
    const res = await api.get("/notifications/subscriptions", userToken);
    expect(res.status).toBe(200);
  });

  test("PUT /notifications/subscriptions вҖ” can opt out of a category", async () => {
    const res = await api.patch(
      "/notifications/subscriptions",
      { category: "announcement", isOptIn: false },
      userToken
    );
    // Accept 200 or 201 depending on upsert behavior
    expect([200, 201]).toContain(res.status);
  });
});

// в”Җв”Җв”Җ Internal endpoints в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

describe("Internal notification endpoints", () => {
  test("POST /internal/notifications/dispatch вҖ” requires internal API key", async () => {
    // Without key вҖ” should fail
    const noKey = await fetch(`${BASE_URL}/api/v1/internal/notifications/dispatch`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
    });
    expect([401, 403]).toContain(noKey.status);
  });

  test("POST /internal/notifications/dispatch вҖ” succeeds with valid key", async () => {
    const res = await fetch(`${BASE_URL}/api/v1/internal/notifications/dispatch`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "X-Internal-Key": INTERNAL_KEY,
      },
    });
    expect(res.status).toBe(200);
  });

  test("POST /internal/notifications/retry вҖ” requires internal API key", async () => {
    const noKey = await fetch(`${BASE_URL}/api/v1/internal/notifications/retry`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
    });
    expect([401, 403]).toContain(noKey.status);
  });

  test("POST /internal/notifications/retry вҖ” succeeds with valid key", async () => {
    const res = await fetch(`${BASE_URL}/api/v1/internal/notifications/retry`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "X-Internal-Key": INTERNAL_KEY,
      },
    });
    expect(res.status).toBe(200);
  });
});
"}

