139	  input: BulkContentInput
140	): Promise<BulkActionResult[]> {
141	  const results: BulkActionResult[] = [];
142	
143	  for (const threadId of input.threadIds) {
144	    try {
145	      const thread = await threadRepository.findById(threadId, organizationId);
146	      if (!thread) {
