148	        continue;
149	      }
150	
151	      if (input.action === "archive_threads") {
152	        if (thread.state === "ARCHIVED") {
153	          results.push({ id: threadId, status: "skipped", reason: "already archived" });
154	          continue;
155	        }
156	        await threadRepository.update(threadId, { state: "ARCHIVED" });
157	      } else if (input.action === "lock_threads") {
158	        if (thread.state !== "ACTIVE") {
159	          results.push({ id: threadId, status: "skipped", reason: `state is ${thread.state}` });
160	          continue;
161	        }
162	        await threadRepository.update(threadId, { state: "LOCKED" });
163	      } else if (input.action === "delete_threads") {
164	        const now = new Date();
165	        const expiresAt = new Date(
166	          now.getTime() + config.forum.recycleBinRetentionDays * 86_400_000
167	        );
