174	          expiresAt,
175	        });
176	      }
177	
178	      await auditRepository.create({
179	        organizationId,
180	        actorId,
181	        eventType: `thread.bulk_${input.action}`,
182	        resourceType: "Thread",
183	        resourceId: threadId,
184	      });
185	
186	      results.push({ id: threadId, status: "ok" });
187	    } catch (err) {
188	      results.push({
189	        id: threadId,
190	        status: "failed",
191	        reason: (err as Error).message,
192	      });
193	    }
194	  }
