1	import { Thread, ThreadState, Prisma } from "@prisma/client";
2	import { prisma } from "../lib/prisma";
3	
4	export interface CreateThreadInput {
5	  organizationId: string;
6	  sectionId: string;
7	  subsectionId?: string;
8	  authorId: string;
9	  title: string;
10	  body: string;
11	  isFeatured?: boolean;
12	  tagIds?: string[];
13	}
14	
15	export interface QueryThreadsInput {
16	  organizationId: string;
17	  sectionId?: string;
18	  subsectionId?: string;
19	  state?: ThreadState;
20	  isPinned?: boolean;
21	  isFeatured?: boolean;
22	  tagSlug?: string;
23	  page: number;
24	  pageSize: number;
25	}
26	
27	// Include shape used consistently across the app
28	const threadInclude = {
29	  author: { select: { id: true, username: true, role: true } },
30	  tags: { include: { tag: { select: { id: true, name: true, slug: true } } } },
31	} satisfies Prisma.ThreadInclude;
32	
33	export type ThreadWithIncludes = Prisma.ThreadGetPayload<{
34	  include: typeof threadInclude;
35	}>;
36	
37	export const threadRepository = {
38	  async create(data: CreateThreadInput): Promise<ThreadWithIncludes> {
39	    const { tagIds = [], ...rest } = data;
40	    return prisma.thread.create({
41	      data: {
42	        ...rest,
43	        tags: { create: tagIds.map((tagId) => ({ tagId })) },
44	      },
45	      include: threadInclude,
46	    });
47	  },
48	
49	  async findMany(
50	    input: QueryThreadsInput
51	  ): Promise<{ data: ThreadWithIncludes[]; total: number }> {
52	    const { organizationId, page, pageSize, tagSlug, ...filters } = input;
53	    const skip = (page - 1) * pageSize;
54	
55	    const where: Prisma.ThreadWhereInput = {
56	      organizationId,
57	      deletedAt: null,
58	      ...(filters.sectionId && { sectionId: filters.sectionId }),
59	      ...(filters.subsectionId && { subsectionId: filters.subsectionId }),
60	      ...(filters.state && { state: filters.state }),
61	      ...(filters.isPinned !== undefined && { isPinned: filters.isPinned }),
62	      ...(filters.isFeatured !== undefined && { isFeatured: filters.isFeatured }),
63	      ...(tagSlug && { tags: { some: { tag: { slug: tagSlug } } } }),
64	    };
65	
66	    const [data, total] = await prisma.$transaction([
67	      prisma.thread.findMany({
68	        where,
69	        orderBy: [{ isPinned: "desc" }, { createdAt: "desc" }],
70	        skip,
71	        take: pageSize,
72	        include: threadInclude,
73	      }),
74	      prisma.thread.count({ where }),
75	    ]);
76	
77	    return { data, total };
78	  },
79	
80	  findById(
81	    id: string,
82	    organizationId: string
83	  ): Promise<ThreadWithIncludes | null> {
84	    return prisma.thread.findFirst({
85	      where: { id, organizationId, deletedAt: null },
86	      include: threadInclude,
87	    });
88	  },
89	
90	  update(
91	    id: string,
92	    data: Partial<Pick<Thread, "title" | "body" | "state" | "isPinned" | "isFeatured" | "deletedAt">>
93	  ): Promise<Thread> {
94	    return prisma.thread.update({ where: { id }, data });
95	  },
96	
97	  countPinned(organizationId: string, sectionId: string): Promise<number> {
98	    return prisma.thread.count({
99	      where: { organizationId, sectionId, isPinned: true, deletedAt: null },
100	    });
101	  },
102	
103	  softDelete(id: string, deletedAt: Date): Promise<Thread> {
104	    return prisma.thread.update({ where: { id }, data: { deletedAt } });
105	  },
106	};
