17	export async function createFeatureFlag(
18	  organizationId: string,
19	  actorId: string,
20	  input: CreateFeatureFlagInput
21	): Promise<FeatureFlag> {
22	  const existing = await featureFlagRepository.findByKey(organizationId, input.key);
23	  if (existing) {
24	    throw new AppError(
