50	export async function updateFeatureFlag(
51	  organizationId: string,
52	  key: string,
53	  actorId: string,
54	  input: UpdateFeatureFlagInput
55	): Promise<FeatureFlag> {
56	  const existing = await featureFlagRepository.findByKey(organizationId, key);
57	  if (!existing) {
58	    throw new AppError(404, ErrorCode.NOT_FOUND, `Feature flag "${key}" not found`);
59	  }
60	
61	  const updated = await featureFlagRepository.update(organizationId, key, input);
62	
63	  // Audit every toggle вҖ” this is a config change
64	  await auditRepository.create({
65	    organizationId,
66	    actorId,
67	    eventType: "feature_flag.updated",
68	    resourceType: "FeatureFlag",
69	    resourceId: existing.id,
70	    details: {
71	      key,
72	      previousValue: existing.value,
73	      newValue: updated.value,
74	      description: input.description,
75	    },
76	  });
77	
78	  return updated;
79	}
