42	export async function createThread(
43	  organizationId: string,
44	  authorId: string,
45	  input: CreateThreadInput
46	): Promise<ThreadWithIncludes> {
47	  // в”Җв”Җ Tenant isolation: verify all referenced IDs belong to this org в”Җв”Җ
48	
49	  // 1. Section must belong to this organization
50	  const section = await sectionRepository.findById(input.sectionId, organizationId);
51	  if (!section) {
52	    throw new AppError(
