64	    );
65	    if (!subsection) {
66	      throw new AppError(
67	        400,
68	        ErrorCode.TENANT_VIOLATION,
69	        "Subsection not found in the specified section"
70	      );
71	    }
72	  }
73	
74	  // 3. All tag IDs must belong to this organization
75	  if (input.tagIds && input.tagIds.length > 0) {
76	    for (const tagId of input.tagIds) {
77	      const tag = await tagRepository.findById(tagId, organizationId);
78	      if (!tag) {
79	        throw new AppError(
80	          400,
81	          ErrorCode.TENANT_VIOLATION,
82	          `Tag '${tagId}' not found in your organization`
83	        );
84	      }
85	    }
86	  }
87	
88	  const thread = await threadRepository.create({
89	    ...input,
90	    organizationId,
91	    authorId,
92	  });
93	
94	  await auditRepository.create({
95	    organizationId,
96	    actorId: authorId,
97	    eventType: "thread.created",
98	    resourceType: "Thread",
99	    resourceId: thread.id,
100	    details: { title: thread.title, sectionId: thread.sectionId },
101	  });
102	
103	  void analyticsService.recordEvent({
104	    organizationId,
105	    userId: authorId,
106	    eventType: EVENT.POST_CREATED,
107	    resourceType: "Thread",
108	    resourceId: thread.id,
109	  });
