317	export async function createReply(
318	  organizationId: string,
319	  authorId: string,
320	  threadId: string,
321	  input: CreateReplyInput
322	): Promise<ReplyWithAuthor> {
323	  const thread = await getThread(threadId, organizationId);
324	
325	  if (thread.state === ThreadState.LOCKED) {
326	    throw new AppError(
327	      422,
328	      ErrorCode.THREAD_LOCKED,
329	      "Thread is locked and cannot accept new replies"
330	    );
331	  }
332	  if (thread.state === ThreadState.ARCHIVED) {
333	    throw new AppError(
334	      422,
335	      ErrorCode.THREAD_ARCHIVED,
336	      "Thread is archived and cannot accept new replies"
337	    );
338	  }
339	
340	  let depth = 1;
341	  const parentReplyId = input.parentReplyId ?? undefined;
342	
343	  if (parentReplyId) {
344	    const parent = await replyRepository.findParent(parentReplyId, threadId);
345	    if (!parent) {
346	      throw new AppError(404, ErrorCode.NOT_FOUND, "Parent reply not found");
347	    }
348	    depth = parent.depth + 1;
349	    if (depth > config.forum.maxReplyDepth) {
350	      throw new AppError(
351	        422,
352	        ErrorCode.REPLY_DEPTH_EXCEEDED,
353	        `Reply nesting exceeds the maximum depth of ${config.forum.maxReplyDepth}`
354	      );
355	    }
356	  }
357	
358	  const reply = await replyRepository.create({
359	    organizationId,
360	    threadId,
361	    authorId,
362	    parentReplyId,
363	    depth,
364	    body: input.body,
365	  });
366	
367	  await auditRepository.create({
368	    organizationId,
369	    actorId: authorId,
370	    eventType: "reply.created",
371	    resourceType: "Reply",
372	    resourceId: reply.id,
373	    details: { threadId, depth },
374	  });
375	
376	  void notifyNewReply(threadId, organizationId, authorId, input.body);
377	
378	  void analyticsService.recordEvent({
379	    organizationId,
380	    userId: authorId,
381	    eventType: EVENT.POST_CREATED,
382	    resourceType: "Reply",
383	    resourceId: reply.id,
384	  });
385	  void analyticsService.recordEvent({
386	    organizationId,
387	    userId: authorId,
388	    eventType: EVENT.ENGAGEMENT,
389	    resourceType: "Thread",
390	    resourceId: threadId,
391	  });
392	
393	  return reply;
394	}
