141	
142	export interface BulkActionResult {
143	  id: string;
144	  status: "ok" | "skipped" | "failed";
145	  reason?: string;
146	}
147	
148	export async function bulkContentAction(
149	  organizationId: string,
150	  actorId: string,
151	  input: BulkContentInput
152	): Promise<BulkActionResult[]> {
153	  const results: BulkActionResult[] = [];
154	
155	  for (const threadId of input.threadIds) {
156	    try {
157	      const thread = await threadRepository.findById(threadId, organizationId);
158	      if (!thread) {
159	        results.push({ id: threadId, status: "skipped", reason: "not found" });
160	        continue;
161	      }
162	
163	      if (input.action === "archive_threads") {
164	        if (thread.state === "ARCHIVED") {
165	          results.push({ id: threadId, status: "skipped", reason: "already archived" });
166	          continue;
167	        }
168	        await threadRepository.update(threadId, { state: "ARCHIVED" });
169	      } else if (input.action === "lock_threads") {
170	        if (thread.state !== "ACTIVE") {
171	          results.push({ id: threadId, status: "skipped", reason: `state is ${thread.state}` });
172	          continue;
173	        }
174	        await threadRepository.update(threadId, { state: "LOCKED" });
175	      } else if (input.action === "delete_threads") {
176	        const now = new Date();
177	        const expiresAt = new Date(
178	          now.getTime() + config.forum.recycleBinRetentionDays * 86_400_000
179	        );
180	        await threadRepository.softDelete(threadId, now);
181	        await recycleRepository.create({
182	          itemType: "THREAD",
183	          threadId,
184	          deletedById: actorId,
185	          deletedAt: now,
186	          expiresAt,
187	        });
188	      }
189	
190	      await auditRepository.create({
191	        organizationId,
192	        actorId,
193	        eventType: `thread.bulk_${input.action}`,
194	        resourceType: "Thread",
195	        resourceId: threadId,
196	      });
197	
198	      results.push({ id: threadId, status: "ok" });
199	    } catch (err) {
200	      results.push({
201	        id: threadId,
202	        status: "failed",
203	        reason: (err as Error).message,
204	      });
205	    }
206	  }
207	
208	  return results;
209	}
