4	export interface AuditEventInput {
5	  organizationId: string;
6	  actorId?: string;
7	  eventType: string;
8	  resourceType?: string;
9	  resourceId?: string;
10	  details?: Record<string, unknown>;
11	  ipAddress?: string;
12	}
13	
14	/**
15	 * Append-only audit log writer.
16	 * No updates or deletes are ever performed on AuditLog records.
17	 */
18	export async function writeAuditLog(event: AuditEventInput): Promise<void> {
19	  await prisma.auditLog.create({
20	    data: {
21	      organizationId: event.organizationId,
22	      actorId: event.actorId,
23	      eventType: event.eventType,
24	      resourceType: event.resourceType,
25	      resourceId: event.resourceId,
26	      details: (event.details ?? {}) as Prisma.InputJsonValue,
27	      ipAddress: event.ipAddress,
28	    },
29	  });
30	}
31	
32	export async function queryAuditLogs(params: {
33	  organizationId: string;
34	  actorId?: string;
35	  eventType?: string;
36	  page: number;
37	  pageSize: number;
38	}) {
39	  const { organizationId, actorId, eventType, page, pageSize } = params;
40	  const skip = (page - 1) * pageSize;
41	
42	  const where = {
43	    organizationId,
44	    ...(actorId && { actorId }),
45	    ...(eventType && { eventType }),
46	  };
47	
48	  const [data, total] = await prisma.$transaction([
49	    prisma.auditLog.findMany({
50	      where,
51	      orderBy: { createdAt: "desc" },
52	      skip,
53	      take: pageSize,
54	    }),
55	    prisma.auditLog.count({ where }),
56	  ]);
57	
58	  return { data, total };
59	}
