17	async function purgeExpiredRecycleBinItems(): Promise<void> {
18	  const now = new Date();
19	  const result = await prisma.recycleBinItem.deleteMany({
20	    where: { expiresAt: { lt: now } },
21	  });
22	  if (result.count > 0) {
23	    logger.info("Purged expired recycle bin items", { count: result.count });
24	  }
25	}
26	
27	async function runRiskRulesForAllOrgs(): Promise<void> {
28	  const orgs = await prisma.organization.findMany({
29	    where: { isActive: true },
30	    select: { id: true },
31	  });
32	
33	  await Promise.allSettled(
34	    orgs.map((org) =>
35	      runRiskRules(org.id).catch((err) =>
36	        logger.error("runRiskRules failed for org", {
37	          orgId: org.id,
38	          error: (err as Error).message,
39	        })
40	      )
41	    )
42	  );
43	}
