47	  execFile("bash", [scriptPath], (err, stdout, stderr) => {
48	    if (err) {
49	      logger.error("Nightly backup failed", { error: err.message, stderr });
50	    } else {
51	      logger.info("Nightly backup completed", { output: stdout.trim() });
52	    }
53	  });
54	}
