56	// в”Җв”Җв”Җ Scheduler в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
57	
58	export function startScheduler(): void {
59	  if (started) return;
60	  started = true;
61	
62	  // Every minute: dispatch pending notifications whose scheduledAt has passed
63	  cron.schedule("* * * * *", async () => {
64	    try {
65	      await dispatchDueNotifications();
66	    } catch (err) {
67	      logger.error("dispatchDueNotifications job failed", {
68	        error: (err as Error).message,
69	      });
70	    }
71	  });
72	
73	  // Every 5 minutes: retry failed notifications within the 24-hour window
74	  cron.schedule("*/5 * * * *", async () => {
75	    try {
76	      await retryFailedNotifications();
77	    } catch (err) {
78	      logger.error("retryFailedNotifications job failed", {
79	        error: (err as Error).message,
80	      });
81	    }
82	  });
83	
84	  // Every 15 minutes: run risk detection rules across all active orgs
85	  cron.schedule("*/15 * * * *", async () => {
86	    try {
87	      await runRiskRulesForAllOrgs();
88	    } catch (err) {
89	      logger.error("runRiskRules job failed", {
90	        error: (err as Error).message,
91	      });
92	    }
93	  });
94	
95	  // Daily at 02:00 UTC: purge expired recycle bin items
96	  cron.schedule("0 2 * * *", async () => {
97	    try {
98	      await purgeExpiredRecycleBinItems();
99	    } catch (err) {
100	      logger.error("purgeExpiredRecycleBinItems job failed", {
101	        error: (err as Error).message,
102	      });
103	    }
104	  });
105	
106	  // Every hour: purge expired revoked tokens
107	  cron.schedule("0 * * * *", async () => {
108	    try {
109	      const result = await prisma.revokedToken.deleteMany({
110	        where: { expiresAt: { lt: new Date() } },
111	      });
112	      if (result.count > 0) {
113	        logger.info("Purged expired revoked tokens", { count: result.count });
114	      }
115	    } catch (err) {
116	      logger.error("purgeExpiredRevokedTokens job failed", {
117	        error: (err as Error).message,
118	      });
119	    }
120	  });
121	
122	  // Daily at 02:30 UTC: nightly database backup with 14-day retention
123	  cron.schedule("30 2 * * *", () => {
124	    try {
125	      runNightlyBackup();
126	    } catch (err) {
127	      logger.error("runNightlyBackup job failed", {
128	        error: (err as Error).message,
129	      });
130	    }
131	  });
132	
133	  logger.info("Background scheduler started", {
134	    jobs: [
135	      "dispatchNotifications (every 1 min)",
136	      "retryNotifications (every 5 min)",
137	      "riskRules (every 15 min)",
138	      "recycleBinPurge (daily 02:00 UTC)",
139	      "revokedTokenPurge (every 1 hour)",
140	      "nightlyBackup (daily 02:30 UTC)",
141	    ],
142	  });
143	}
