    );
  });

  test("reduce pin limit to 1 in DB вҶ’ 2nd pin rejected", async () => {
    // Set pin limit to 1
    await api.patch(
      "/admin/feature-flags/forum.max_pinned_per_section",
      { description: "1" },
      adminToken
    );

    // Create 2 threads in the pin section
