1	/**
2	 * Notification service вҖ” in-app delivery ONLY.
3	 *
4	 * EXTERNAL CHANNELS EXPLICITLY DISABLED:
5	 *   - SMS: not implemented, no SMS provider configured
6	 *   - Email: not implemented, no email provider configured
7	 *   - WeChat / push: not implemented, no push provider configured
8	 *
9	 * All notifications are stored in the `notifications` table and delivered
10	 * when the user next polls GET /api/v1/notifications.
11	 */
12	
13	import { config } from "../config";
14	import { logger } from "../lib/logger";
15	import { notificationRepository } from "../repositories/notification.repository";
16	
17	// в”Җв”Җв”Җ Notification categories в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
18	
19	export const CATEGORY = {
20	  REPLY: "reply",
21	  MODERATION: "moderation",
22	  ANNOUNCEMENT: "announcement",
23	  SECURITY: "security",
24	} as const;
25	
26	// в”Җв”Җв”Җ Internal: create one notification for a user (subscription-aware) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
27	
28	async function createNotification(params: {
29	  organizationId: string;
30	  userId: string;
31	  category: string;
32	  title: string;
33	  body: string;
34	  scheduledAt?: Date;
35	}): Promise<void> {
36	  const { scheduledAt = new Date(), ...rest } = params;
37	
38	  // Security notices bypass subscription opt-out (default opt-in, cannot disable)
39	  if (rest.category !== CATEGORY.SECURITY) {
40	    const sub = await notificationRepository.getSubscription(
41	      rest.userId,
42	      rest.category
43	    );
44	    // Explicit opt-out recorded вҶ’ skip
45	    if (sub && !sub.isOptIn) return;
46	  }
47	
48	  await notificationRepository.create({ ...rest, scheduledAt });
49	}
50	
51	// в”Җв”Җв”Җ Event triggers в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
52	
53	/**
54	 * Notify the thread author when someone replies to their thread.
55	 * The replying user does NOT receive a self-notification.
56	 */
57	export async function notifyNewReply(
58	  threadId: string,
59	  organizationId: string,
60	  replyAuthorId: string,
61	  bodyPreview: string
62	): Promise<void> {
63	  try {
64	    const threadAuthorId = await notificationRepository.findThreadAuthorId(
65	      threadId,
66	      organizationId
67	    );
68	    if (!threadAuthorId || threadAuthorId === replyAuthorId) return;
69	
70	    await createNotification({
71	      organizationId,
72	      userId: threadAuthorId,
73	      category: CATEGORY.REPLY,
74	      title: "New reply on your thread",
75	      body: bodyPreview.slice(0, 200),
76	    });
77	  } catch (err) {
78	    // Notification failures must never break the primary operation
79	    logger.error("notifyNewReply failed", { threadId, error: (err as Error).message });
80	  }
81	}
82	
83	/**
84	 * Notify a user who has been banned or muted (security category вҖ” cannot opt out).
85	 */
86	export async function notifyModerationAction(
87	  targetUserId: string,
88	  organizationId: string,
89	  action: "banned" | "unbanned" | "muted" | "unmuted",
90	  details: { reason?: string; muteUntil?: string }
91	): Promise<void> {
92	  try {
93	    const titles: Record<typeof action, string> = {
94	      banned: "Your account has been suspended",
95	      unbanned: "Your account suspension has been lifted",
96	      muted: "You have been muted",
97	      unmuted: "Your mute has been lifted",
98	    };
99	
100	    let body = titles[action];
101	    if (action === "muted" && details.muteUntil) {
102	      body += ` until ${details.muteUntil}`;
103	    }
104	    if (details.reason) {
105	      body += `. Reason: ${details.reason}`;
106	    }
107	
108	    await createNotification({
109	      organizationId,
110	      userId: targetUserId,
111	      category: CATEGORY.SECURITY, // Always delivered вҖ” security category
112	      title: titles[action],
113	      body,
114	    });
115	  } catch (err) {
116	    logger.error("notifyModerationAction failed", {
117	      targetUserId,
118	      action,
119	      error: (err as Error).message,
120	    });
121	  }
122	}
123	
124	/**
125	 * Fan out an announcement notification to all active users in the org.
126	 * Uses ANNOUNCEMENT category вҖ” users may opt out.
127	 */
128	export async function notifyAnnouncementPublished(
129	  organizationId: string,
130	  title: string,
131	  body: string
132	): Promise<void> {
133	  try {
134	    const userIds = await notificationRepository.findOrgUserIds(organizationId);
135	
136	    // Fan out one notification per user (fire-and-forget, log errors per user)
137	    await Promise.allSettled(
138	      userIds.map((userId) =>
139	        createNotification({
140	          organizationId,
141	          userId,
142	          category: CATEGORY.ANNOUNCEMENT,
143	          title,
144	          body: body.slice(0, 500),
145	        })
146	      )
147	    );
148	  } catch (err) {
149	    logger.error("notifyAnnouncementPublished failed", {
150	      organizationId,
151	      error: (err as Error).message,
152	    });
153	  }
154	}
155	
156	// в”Җв”Җв”Җ Scheduled jobs в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
157	
158	/**
159	 * Mark all due PENDING notifications as DELIVERED.
160	 * Called by the scheduler every minute.
161	 */
162	export async function dispatchDueNotifications(): Promise<number> {
163	  const now = new Date();
164	  const due = await notificationRepository.findDueForDispatch(now);
165	
166	  let dispatched = 0;
167	  for (const n of due) {
168	    try {
169	      await notificationRepository.markDelivered(n.id, now);
170	      dispatched++;
171	    } catch (err) {
172	      logger.error("Failed to deliver notification", {
173	        notificationId: n.id,
174	        error: (err as Error).message,
175	      });
176	    }
177	  }
178	
179	  if (dispatched > 0) {
180	    logger.info("Notifications dispatched", { count: dispatched });
181	  }
182	  return dispatched;
183	}
184	
185	/**
186	 * Re-queue FAILED notifications that are within the retry window.
187	 * Exponential backoff: delays are taken from config.notifications.retryDelaysMinutes.
188	 * After maxRetries attempts the notification is marked DELIVERED (best-effort).
189	 * Called by the scheduler every 5 minutes.
190	 */
191	export async function retryFailedNotifications(): Promise<number> {
192	  const now = new Date();
193	  const windowStart = new Date(
194	    now.getTime() - config.notifications.retryWindowHours * 3_600_000
195	  );
196	
197	  const failed = await notificationRepository.findFailedForRetry(
198	    config.notifications.maxRetries,
199	    windowStart,
200	    now
201	  );
202	
203	  let retried = 0;
204	  for (const n of failed) {
205	    const newCount = n.retryCount + 1;
206	    const delayMinutes =
207	      config.notifications.retryDelaysMinutes[newCount - 1] ??
208	      config.notifications.retryDelaysMinutes.at(-1) ??
209	      30;
210	    const nextRetryAt = new Date(now.getTime() + delayMinutes * 60_000);
211	
212	    try {
213	      if (newCount >= config.notifications.maxRetries) {
214	        // Final attempt exhausted вҖ” mark as permanently failed
215	        await notificationRepository.markFailed(n.id, newCount, null);
216	      } else {
217	        await notificationRepository.scheduleRetry(n.id, newCount, nextRetryAt);
218	      }
219	      retried++;
220	    } catch (err) {
221	      logger.error("Retry update failed", {
222	        notificationId: n.id,
223	        error: (err as Error).message,
224	      });
225	    }
226	  }
227	
228	  if (retried > 0) {
229	    logger.info("Failed notifications retried", { count: retried });
230	  }
231	  return retried;
232	}
