158	/**
159	 * Mark all due PENDING notifications as DELIVERED.
160	 * Called by the scheduler every minute.
161	 */
162	export async function dispatchDueNotifications(): Promise<number> {
163	  const now = new Date();
164	  const due = await notificationRepository.findDueForDispatch(now);
165	
166	  let dispatched = 0;
167	  for (const n of due) {
168	    try {
169	      await notificationRepository.markDelivered(n.id, now);
170	      dispatched++;
171	    } catch (err) {
172	      logger.error("Failed to deliver notification", {
173	        notificationId: n.id,
174	        error: (err as Error).message,
175	      });
176	      // Mark as FAILED so the retry worker picks it up with exponential backoff
177	      try {
178	        const delayMinutes = config.notifications.retryDelaysMinutes[0] ?? 1;
179	        const nextRetryAt = new Date(now.getTime() + delayMinutes * 60_000);
180	        await notificationRepository.markFailed(n.id, n.retryCount + 1, nextRetryAt);
181	      } catch (markErr) {
182	        logger.error("Failed to mark notification as FAILED", {
183	          notificationId: n.id,
184	          error: (markErr as Error).message,
185	        });
186	      }
187	    }
188	  }
189	
190	  if (dispatched > 0) {
191	    logger.info("Notifications dispatched", { count: dispatched });
192	  }
193	  return dispatched;
194	}
195	
196	/**
197	 * Re-queue FAILED notifications that are within the retry window.
198	 * Exponential backoff: delays are taken from config.notifications.retryDelaysMinutes.
199	 * After maxRetries attempts the notification is marked DELIVERED (best-effort).
200	 * Called by the scheduler every 5 minutes.
201	 */
202	export async function retryFailedNotifications(): Promise<number> {
203	  const now = new Date();
204	  const windowStart = new Date(
205	    now.getTime() - config.notifications.retryWindowHours * 3_600_000
206	  );
207	
208	  const failed = await notificationRepository.findFailedForRetry(
209	    config.notifications.maxRetries,
210	    windowStart,
211	    now
212	  );
213	
214	  let retried = 0;
215	  for (const n of failed) {
216	    const newCount = n.retryCount + 1;
217	    const delayMinutes =
218	      config.notifications.retryDelaysMinutes[newCount - 1] ??
219	      config.notifications.retryDelaysMinutes.at(-1) ??
220	      30;
221	    const nextRetryAt = new Date(now.getTime() + delayMinutes * 60_000);
222	
223	    try {
224	      if (newCount >= config.notifications.maxRetries) {
225	        // Final attempt exhausted вҖ” mark as permanently failed
226	        await notificationRepository.markFailed(n.id, newCount, null);
227	      } else {
228	        await notificationRepository.scheduleRetry(n.id, newCount, nextRetryAt);
229	      }
230	      retried++;
231	    } catch (err) {
232	      logger.error("Retry update failed", {
233	        notificationId: n.id,
234	        error: (err as Error).message,
235	      });
236	    }
237	  }
238	
239	  if (retried > 0) {
240	    logger.info("Failed notifications retried", { count: retried });
241	  }
242	  return retried;
243	}
244

85	      }
86	    }
87	  }
